CREATE DATABASE /*!32312 IF NOT EXISTS*/`e-libstore` /*!40100 DEFAULT CHARACTER SET latin1 */;

USE `e-libstore`;

/*Table structure for table `books` */

DROP TABLE IF EXISTS `books`;

CREATE TABLE `books` (
  `bookid` int(11) NOT NULL auto_increment,
  `booktitle` varchar(50) default NULL,
  `bookprice` decimal(10,2) default NULL,
  `bookauthor` varchar(50) default NULL,
  `bookcover` mediumblob,
  `bookcondition` varchar(10) default NULL,
  `userid` int(11) default NULL,
  `status` varchar(20) default 'AVAILABLE',
  PRIMARY KEY  (`bookid`),
  KEY `fk_books_users` (`userid`),
  CONSTRAINT `fk_books_users` FOREIGN KEY (`userid`) REFERENCES `users` (`userid`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

