/*Table structure for table `cart` */

DROP TABLE IF EXISTS `cart`;

CREATE TABLE `cart` (
  `cartid` int(11) NOT NULL auto_increment,
  `userid` int(12) default NULL,
  `bookid` int(11) default NULL,
  PRIMARY KEY  (`cartid`),
  UNIQUE KEY `unique_cart` (`userid`,`bookid`),
  KEY `fk_cart_book` (`bookid`),
  CONSTRAINT `fk_cart_book` FOREIGN KEY (`bookid`) REFERENCES `books` (`bookid`),
  CONSTRAINT `fk_cart_user` FOREIGN KEY (`userid`) REFERENCES `users` (`userid`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Data for the table `cart` */

insert  into `cart`(`cartid`,`userid`,`bookid`) values (3,1,1),(2,1,3),(4,7,3);

/*Table structure for table `users` */

DROP TABLE IF EXISTS `users`;

CREATE TABLE `users` (
  `userid` int(10) NOT NULL auto_increment,
  `username` varchar(20) NOT NULL default '',
  `userpassword` varchar(30) NOT NULL default '',
  `usermail` varchar(30) NOT NULL,
  `usercontact` varchar(15) NOT NULL,
  PRIMARY KEY  (`userid`),
  UNIQUE KEY `username` (`username`),
  UNIQUE KEY `unique_usermail` (`usermail`),
  UNIQUE KEY `unique_usercontact` (`usercontact`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

